#include<bits/stdc++.h>
using namespace std;
int n;
int a[100010],b[100010];
struct st
{
	int lg[100010];
	int f[100010][22],f1[100010][22];
	void init()
	{
		lg[1]=0;
		for(int i=2;i<=n;i++)
		{
			lg[i]=lg[i/2]+1;
		}
		for(int i=1;i<=n;i++)
		{
			f[i][0]=f1[i][0]=a[i];
		}
		for(int j=1;j<=lg[n];j++)
		{
			for(int i=1;i<=n-(1<<j)+1;i++)
			{
				f[i][j]=max(f[i][j-1],f[i+(1<<(j-1))][j-1]);
				f1[i][j]=min(f1[i][j-1],f1[i+(1<<(j-1))][j-1]);
			}
		}
	}
	int getmax(int l,int r)
	{
        if(r<l)
        {
            return 0;
        }
		int temp=lg[r-l+1];
		return max(f[l][temp],f[r-(1<<temp)+1][temp]);
	}
	int getmin(int l,int r)
	{
		int temp=lg[r-l+1];
		return min(f1[l][temp],f1[r-(1<<temp)+1][temp]);
	}
}s;
bool check(int x,int mid)
{
    if(s.getmax(max(1,x-mid),x-1)>=b[x]||s.getmax(x+1,min(n,x+mid))>=b[x])
    {
        return true;
    }
    if(x-mid<1)
    {
        if(s.getmax(x-mid+n,n)>=b[x])
        {
            return true;
        }
    }
    if(x+mid>n)
    {
        if(s.getmax(1,x+mid-n)>=b[x])
        {
            return true;
        }
    }
    return false;
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&b[i]);
    }
    s.init();
    for(int i=1;i<=n;i++)
    {
        int l=1,r=n-1,best=-1;
        while(l<=r)
        {
            int mid=(l+r)/2;
            if(check(i,mid))
            {
                best=mid;
                r=mid-1;
            }
            else
            {
                l=mid+1;
            }
        }
        printf("%d ",best);
    }
    return 0;
}
